// C0684 · REST CRUD JSON (GET/POST/PUT/DELETE)
import Koa from "koa";
import Router from "@koa/router";
import bodyParser from "koa-bodyparser"; // npm i koa-bodyparser
const app = new Koa();
const router = new Router();
app.use(bodyParser());

const items = new Map(); let seq=1;

router.get("/items", (ctx)=>{ ctx.body=[...items.values()]; });
router.post("/items", (ctx)=>{
  const it={ id: seq++, name: String(ctx.request.body?.name||"") };
  items.set(it.id, it);
  ctx.status=201; ctx.body=it;
});
router.delete("/items/:id", (ctx)=>{ items.delete(Number(ctx.params.id)); ctx.status=204; });

app.use(router.routes()).use(router.allowedMethods());

