import Koa from "koa";
import Router from "@koa/router";
import jwt from "jsonwebtoken";
import koaJwt from "koa-jwt"; // npm i koa-jwt jsonwebtoken
const app = new Koa();
const router = new Router();
const SECRET = process.env.JWT_SECRET || "dev-secret";

