// C0688 · Auth por sesión (login/logout)
import Koa from "koa";
import Router from "@koa/router";
import session from "koa-session"; // npm i koa-session
const app = new Koa();
const router = new Router();
app.keys = [process.env.SESSION_SECRET || "dev-secret"];
app.use(session(app));

router.post("/login", (ctx)=>{ ctx.session.user = { id:"user-1" }; ctx.body={ ok:true }; });
router.post("/logout", (ctx)=>{ ctx.session = null; ctx.body={ ok:true }; });
router.get("/me", (ctx)=>{
  if(!ctx.session?.user){ ctx.status=401; ctx.body={ error:"unauthorized" }; return; }
  ctx.body = ctx.session.user;
});

app.use(router.routes()).use(router.allowedMethods());

