// C0689 · Validación de entrada (schema)
import Koa from "koa";
import Router from "@koa/router";
import bodyParser from "koa-bodyparser";
import { z } from "zod"; // npm i zod
const app = new Koa();
const router = new Router();
app.use(bodyParser());

const Schema = z.object({ name: z.string().min(1), age: z.number().int().min(0) });

router.post("/users", (ctx)=>{
  const parsed = Schema.safeParse(ctx.request.body);
  if(!parsed.success){ ctx.status=400; ctx.body={ error:"validation", details: parsed.error.flatten() }; return; }
  ctx.status=201; ctx.body=parsed.data;
});

